# Scratch: เหมือนบล็อก "ถ้า...แล้ว" เลย
อากาศ = input("วันนี้อากาศเป็นยังไง? (แดด/ฝน): ")
if อากาศ == "แดด":
    print("ไปเล่นข้างนอกกัน!")
else:
    print("อยู่บ้านเขียนโปรแกรมกัน!")

# Scratch: เหมือนบล็อก "ถ้า...แล้ว ไม่ก็ถ้า...แล้ว" เลย
ชั่วโมง = int(input("ตอนนี้กี่โมง? (0-23): "))
if ชั่วโมง < 10:
    print("อรุณสวัสดิ์!")
elif ชั่วโมง < 17:
    print("สวัสดีค่ะ!")
else:
    print("ราตรีสวัสดิ์!")

